FINAL_DATA AS
(
	SELECT
        --<GH_Rewrite_Work>
        DMX.REPORTABLE_CFTC,
        DMX.REPORTABLE_CSA,
        --</GH_Rewrite_Work>

		DMX.CLEARED,

		--<GH_Rewrite_Work>
		-- champ splitt  CFTC/CSA, ne s'applique pas pour COM
		--DMX.CLEAR_EXCEPTION2,
		CAST(NULL AS VARCHAR2(1 BYTE)) AS CLEAR_EXCEPTION2_CFTC,
		CAST(NULL AS VARCHAR2(1 BYTE)) AS CLEAR_EXCEPTION2_CSA,
		--</GH_Rewrite_Work>

		DMX.REPORTING_PARTY_LEI,

		DMX.COUNTERPARTY_LEI,

		DMX.PARTY_TYP2,

		DMX.FINANCIAL_ENTITY1,

		DMX.FINANCIAL_ENTITY2,

		CASE
            WHEN DMX.THD_TRD_QUALIF_VAL IN('OPT','OSWP') THEN
                CASE
                    WHEN DMX.THD_BUY_SELL_IND = 'BUY' THEN DMX.REPORTING_PARTY_LEI
                    ELSE DMX.COUNTERPARTY_LEI
                END
            ELSE NULL
		END AS BUYER,

		CASE
            WHEN DMX.THD_TRD_QUALIF_VAL IN('OPT','OSWP') THEN
                CASE
                    WHEN DMX.THD_BUY_SELL_IND = 'SELL' THEN DMX.REPORTING_PARTY_LEI
                    ELSE DMX.COUNTERPARTY_LEI
                END
            ELSE NULL
		END AS SELLER,

		CASE
		   WHEN NVL(DMX.THD_TRD_QUALIF_VAL, ' ') != 'SWP' THEN NULL
		   WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.THD_PAY_RECV_IND = 'P' THEN DMX.REPORTING_PARTY_LEI
		   ELSE DMX.COUNTERPARTY_LEI
		END AS PAYER_LEG1,

		CASE
		   WHEN NVL(DMX.THD_TRD_QUALIF_VAL, ' ') != 'SWP' THEN NULL
		   WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.TRP_PAY_RECV_IND_FAR = 'P' THEN DMX.REPORTING_PARTY_LEI
		   ELSE DMX.COUNTERPARTY_LEI
		END AS PAYER_LEG2,

		CASE
		   WHEN NVL(DMX.THD_TRD_QUALIF_VAL, ' ') != 'SWP' THEN NULL
		   WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.THD_PAY_RECV_IND = 'P' THEN DMX.COUNTERPARTY_LEI
		   ELSE DMX.REPORTING_PARTY_LEI
		END AS RECEIVER_LEG1,

		CASE
		   WHEN NVL(DMX.THD_TRD_QUALIF_VAL, ' ') != 'SWP' THEN NULL
		   WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND DMX.TRP_PAY_RECV_IND_FAR = 'P' THEN DMX.COUNTERPARTY_LEI
		   ELSE DMX.REPORTING_PARTY_LEI
		END AS RECEIVER_LEG2,

		DMX.FEDERAL_ENTITY2,

		DMX.CUSTOM_BSK_IND,

		DMX.EVENT_ID,

		DMX.EVENT_TIME,

		DMX.CCF_NOTIONAL_LEG1_CFTC_AMT AS NOTIONAL1,

		DMX.CCF_NOTIONAL_LEG2_CFTC_AMT AS NOTIONAL2,

		DMX.CCF_NOTIONAL_LEG1_CFTC_CCY AS CURR1,

		DMX.CCF_NOTIONAL_LEG2_CFTC_CCY AS CURR2,

------ FIX GIMF-37687, changed the delimiter to ; in the instr function. For some reason, NOTIONAL_AMT_EFFECTI_DATE_LEG1/2 use ';' instead of ','
        CASE
            WHEN INSTR(sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG1, ';', 1, 17) = 0 THEN sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG1
            ELSE SUBSTR(sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG1, 1, INSTR(sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG1,';',1,17) - 1)
        END AS NOTIONAL_AMT_EFFECTI_DATE_LEG1,

        CASE
            WHEN INSTR(sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG2, ';', 1, 17) = 0 THEN sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG2
            ELSE SUBSTR(sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG2, 1, INSTR(sub_notional_amt_effecti_date.NOTIONAL_AMT_EFFECTI_DATE_LEG2,';',1,17) - 1)
        END AS NOTIONAL_AMT_EFFECTI_DATE_LEG2,

        CASE
            WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'Y' OR DMX.THD_PRICE_SCHEDULE_CODE = 'Y' THEN
                CASE
                    WHEN INSTR(DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT_COM,',',1,17) = 0 THEN DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT_COM
                    ELSE SUBSTR(DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT_COM,1,INSTR(DMX.LIST_PERIOD_START_NEAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT_COM,',',1,17) - 1)
                END
            ELSE NULL
        END AS EFFECTI_DATE_NOTIONAL_AMT_LEG1,

        CASE
            WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'Y' OR DMX.THD_PRICE_SCHEDULE_CODE = 'Y' THEN
                CASE
                    WHEN INSTR(DMX.LIST_PERIOD_START_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT_COM,',',1,17) = 0 THEN DMX.LIST_PERIOD_START_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT_COM
