		FROM DS_MUREX DMX
		--<GH_Rewrite_Work>
		CROSS APPLY
		(
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_ASIAN' AND NVL (DMX.THD_CONTRCT_TYPOLOGY_VAL, ' ') != 'CM Simple Option' THEN DMX.THD_UNADJST_LEG1_START_DATE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_OPT_SWAP' OR DMX.THD_CONTRCT_TYPOLOGY_VAL = 'CM Simple Option' THEN DMX.THD_TRD_DATE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_SWAP' AND (DMX.THD_TYPOLOGY_DESC = 'FORWARD STRUCTURE' OR DMX.TRP_ASSET_DESC_NEAR = 'Cryptocurrencies') THEN NVL(DMX.THD_ORIG_EFFECT_DATE, DMX.THD_UNADJST_LEG1_START_DATE)
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_SWAP' THEN DMX.THD_UNADJST_LEG1_START_DATE
                    ELSE NULL
                END AS EFFECTIVE_DATE
            FROM DUAL
		) sub_effective_date

