                CASE
                    WHEN NVL(DMX.SEF_DCM_ANONYM,' ') != 'true'
                    THEN DECODE(DMX.MLG_SID, NULL, 'BIAG', 'ISDA')
                    ELSE NULL
                END AS MASTER_AGREEMENT_TYPE
            FROM DUAL
		) sub_agreement_type

		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('COM_SWAP','COM_OPT_SWAP') THEN
						CASE
							WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN DMX.TRP_ASSET_LABEL_NEAR
							WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN DMX.TRP_ASSET_LABEL_FAR
							ELSE NULL
						END
					ELSE NULL
				END AS ASSET
--				,CASE
--					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('COM_SWAP','COM_OPT_SWAP') THEN
--						CASE
--							WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN DMX.TRP_LEG_UOM_VAL_NEAR
--							WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN DMX.TRP_LEG_UOM_VAL_FAR
--							ELSE NULL
--						END
--					ELSE NULL
--				END AS QUOTATION
			FROM DUAL
		) sub_asset
		LEFT JOIN ISO20022_UNIT_MEASURE_MAP UM_NEAR ON DMX.THD_UOM_VAL = UM_NEAR.INVAL
		LEFT JOIN ISO20022_UNIT_MEASURE_MAP UM_FAR ON NVL(DMX.TRP_LEG_UOM_VAL_FAR,DMX.THD_UOM_VAL) /*sub_asset.QUOTATION*/ = UM_FAR.INVAL
		--LEFT JOIN ISO20022_UNIT_MEASURE_MAP UM_FAR ON sub_asset.QUOTATION = UM_FAR.INVAL
		LEFT JOIN UNDERLYER_ID_MAP UND_NEAR ON NVL (DMX.TRO_ASSET_DESC, DMX.TRP_ASSET_DESC_NEAR) = UND_NEAR.INVAL
		LEFT JOIN UNDERLYER_ID_MAP UND_FAR ON DMX.TRP_ASSET_DESC_FAR = UND_FAR.INVAL
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME LIKE 'COM%' THEN
						CASE
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_ASIAN' AND DMX.THD_CONTRCT_TYPOLOGY_VAL = 'CM Simple Option' THEN DMX.THD_LIVE_QTY_VAL
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_OPT_SWAP' THEN ABS(NVL(DMX.TRO_GLB_QTY,DMX.TRP_GLB_QTY_NEAR)) * UM_NEAR.UOC
							WHEN DMX.THD_TRD_QUALIF_VAL IN ('SWP','OPT') AND NVL (DMX.THD_CONTRCT_TYPOLOGY_VAL,' ') != 'CM Simple Option' THEN
								CASE
									WHEN THD_LAST_NOTIONAL_EVT_DATE IS NULL THEN ABS(NVL (DMX.TRO_GLB_QTY,DMX.TRP_GLB_QTY_NEAR)) * UM_NEAR.UOC
									ELSE DMX.SUM_FFL_PERIOD_QTY_VAL_NEAR_INT * NVL (DMX.TRO_VOL_FACTOR,DMX.TRP_VOL_FACTOR_NEAR) * UM_NEAR.UOC
								END
							ELSE NULL
						END
					ELSE NULL
				END AS TOTAL_QUANTITY1,
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_OPT_SWAP' THEN ABS(NVL (DMX.TRO_GLB_QTY,DMX.TRP_GLB_QTY_NEAR)) * UM_FAR.UOC
					WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' THEN
						CASE
							WHEN DMX.THD_LAST_NOTIONAL_EVT_DATE IS NULL THEN ABS (DMX.TRP_GLB_QTY_FAR) * UM_FAR.UOC
							ELSE DMX.SUM_FFL_PERIOD_QTY_VAL_FAR_INT * DMX.TRP_VOL_FACTOR_FAR * UM_FAR.UOC
						END
					ELSE NULL
				END AS TOTAL_QUANTITY2
			FROM DUAL
		) sub_qty
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN THD_TRD_CLASS_SRC_NAME LIKE 'COM%' THEN
						CASE
							WHEN THD_TRD_CLASS_SRC_NAME = 'COM_OPT_SWAP' OR (THD_TRD_CLASS_SRC_NAME = 'COM_ASIAN' AND DMX.THD_CONTRCT_TYPOLOGY_VAL = 'CM Simple Option') THEN DECODE (TRO_AMEREURO_CODE,'E', 'European','A', 'American','B', 'Bermudan',NULL)
							WHEN THD_TRD_CLASS_SRC_NAME = 'COM_ASIAN' AND NVL (DMX.THD_CONTRCT_TYPOLOGY_VAL,' ') != 'CM Simple Option'
								AND NVL(DMX.FFL_PERIOD_FIRST_FIX_DATE_AT_MIN_FFL_PERIOD_END_DATE_NEAR_INT,TO_DATE('9999-12-31','YYYY-MM-DD')) != NVL(DMX.FFL_PERIOD_LAST_FIX_DATE_AT_MIN_FFL_PERIOD_END_DATE_NEAR_INT,TO_DATE('9999-12-31','YYYY-MM-DD')) THEN 'Asian'
							ELSE DECODE (TRO_AMEREURO_CODE,'E', 'European','A', 'American',NULL)
						END
					ELSE NULL
				END AS EXERCISE
			FROM DUAL
		) sub_exercise
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_QUALIF_VAL IN('OPT','OSWP') THEN
						CASE
							WHEN DMX.THD_SETTL_MOD_CODE = 0 AND NVL (DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN ABS (DMX.THD_INITIALPAYMENT_AMT)
							WHEN DMX.THD_SETTL_MOD_CODE = 6 THEN
							CASE
								WHEN NVL(DMX.SUM_FFL_PREMIUM_AMT_NEAR,0) != 0 THEN ABS (DMX.SUM_FFL_PREMIUM_AMT_NEAR)
								ELSE 0
							END
						ELSE 0
					END
					ELSE NULL
				END AS UPFRONT_FEE_AMOUNT
			FROM DUAL
		) sub_upfront_fee_amt
		CROSS APPLY
		(
			SELECT
--                --<modif evo100>
--                CASE
--                    WHEN DMX.THD_TRD_CLASS_SRC_NAME LIKE 'COM%' AND DMX.THD_TYPOLOGY_DESC = 'FORWARD STRUCTURE' THEN DMX.THD_FWD_PRICE
--                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_SWAP' THEN
--                        CASE
--                            WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN DMX.TRP_PX_RATE_VAL_FAR / NVL(UM_FAR.UOC, 1)
--                            WHEN DMX.INS_INSTR_SRC_NAME = 'WCS BLD CAD_MAV' THEN ABS(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR)
--                            ELSE NULL
--                        END
--                    ELSE NULL
--                END AS PRICE,
--                --</modif evo100>
--				---------------- REGTR-1174 d but du changement
--				CASE
--					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_ASIAN' THEN
--						CASE
--							WHEN INSTR (DMX.THD_UN_PRODUCT_ID_VAL,'Exotic',1) > 0 THEN
--								CASE
--									WHEN DMX.TRO_PUT_CALL_IND IN('R','S','b','G','P','X') THEN DMX.TRO_CAP_STRIKE_PX_VAL / NVL(UM_NEAR.UOC, 1)
--									WHEN DMX.TRO_PUT_CALL_IND = 'B' THEN NULL
--									ELSE DMX.TRO_STRIKE_PX_VAL / NVL (UM_NEAR.UOC, 1)
--								END
--							ELSE DMX.TRO_STRIKE_PX_VAL / NVL (UM_NEAR.UOC, 1)
--						END
--					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_OPT_SWAP' THEN DMX.TRO_STRIKE_PX_VAL / NVL (UM_NEAR.UOC, 1)
--					ELSE NULL
--				END AS STRIKE_PRICE
--				---------------- REGTR-1174 fin du changement
                DMX.CCF_PRICE_CFTC AS PRICE,
                DMX.CCF_STRIKE_PRICE_CFTC AS STRIKE_PRICE
			FROM DUAL
		) sub_price
		CROSS APPLY
		(
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_SWAP' THEN
                        CASE
                            WHEN DMX.THD_TYPOLOGY_DESC = 'FORWARD STRUCTURE' OR DMX.THD_UN_PRODUCT_ID_VAL = 'Commodity:Index:Exotic' OR DMX.INS_INSTR_SRC_NAME = 'WCS BLD CAD_MAV' OR (/*DMX.THD_IDX_NOMINAL*/ DMX.TRP_VOL_FACTOR_FAR < 0 AND DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR < 0) THEN NULL
                            WHEN DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' THEN
                                CASE
                                    WHEN NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR,0) != 0 THEN DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR
                                    WHEN sub_price.PRICE IS NULL THEN 0
                                    ELSE NULL
                                END
                            ELSE NULL
                        END
                    ELSE NULL
                END AS SPREAD1,
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_SWAP' THEN
                        CASE
                            WHEN DMX.THD_TYPOLOGY_DESC = 'FORWARD STRUCTURE' OR DMX.THD_UN_PRODUCT_ID_VAL = 'Commodity:Index:Exotic' OR DMX.INS_INSTR_SRC_NAME = 'WCS BLD CAD_MAV' OR (/*DMX.THD_IDX_NOMINAL*/ DMX.TRP_VOL_FACTOR_FAR < 0 AND DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR < 0) THEN NULL
                            WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                                CASE
                                    WHEN NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_FAR,0) != 0 THEN DMX.TRP_LEG_MARGIN_PX_RATE_VAL_FAR
                                    WHEN sub_price.PRICE IS NULL THEN 0
                                    ELSE NULL
                                END
                            ELSE NULL
                        END
                    ELSE NULL
                END AS SPREAD2
            FROM DUAL
		) sub_spread
		CROSS APPLY
		(
            SELECT
		        CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'Y' OR DMX.THD_PRICE_SCHEDULE_CODE = 'Y' THEN
                        CASE
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_SWAP' /*AND DMX.THD_IDX_NOMINAL < 0*/ AND DMX.TRP_VOL_FACTOR_FAR < 0 AND DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR < 0 THEN DMX.LIST_FUTURE_PERIOD_QTY_X_MARGIN_RATE_NEAR
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('COM_SWAP','COM_OPT_SWAP') THEN
                                CASE
                                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' OR (DMX.THD_TRD_CLASS_SRC_NAME = 'COM_OPT_SWAP' AND PATCH_COM_OPT_SWAP_FIXVAR = 'F')  THEN DMX.LIST_FUTURE_PERIOD_QTY_X_FIX_MARGIN_RATE_FAR
                                    ELSE DMX.LIST_FUTURE_PERIOD_QTY_X_SPOT_PRICE_NEAR
                                END
                            ELSE DMX.LIST_FUTURE_PERIOD_QTY_X_PERIOD_STRIKE_NEAR
                        END
                    ELSE NULL
                END AS NOTIONAL_AMT_EFFECTI_DATE_LEG1,

        --		DECODE
        --		(
        --			DMX.IS_CONSTANT,'Y', NULL,
        --			CASE
        --				WHEN INSTR(DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT,',',1,17) = 0 THEN DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT
        --				ELSE SUBSTR(DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT,1,INSTR(DMX.LIST_REMAIN_CAP_AMT_FAR_INT_FROM_DATE_LAST_EVENT_NO_DISTINCT,',',1,17) - 1)
        --			END
        --		) AS NOTIONAL_AMT_EFFECTI_DATE_LEG2,
                CASE
                    WHEN DMX.THD_NOTIONAL_SCHEDULE_CODE = 'Y' OR DMX.THD_PRICE_SCHEDULE_CODE = 'Y' THEN
                        CASE
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'COM_SWAP' /*AND DMX.THD_IDX_NOMINAL < 0*/ AND DMX.TRP_VOL_FACTOR_FAR < 0 AND DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR < 0 THEN DMX.LIST_FUTURE_PERIOD_QTY_X_MARGIN_RATE_NEAR
                            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('COM_SWAP','COM_OPT_SWAP') THEN
                                CASE
                                    WHEN DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' OR (DMX.THD_TRD_CLASS_SRC_NAME = 'COM_OPT_SWAP' AND PATCH_COM_OPT_SWAP_FIXVAR = 'F')  THEN DMX.LIST_FUTURE_PERIOD_QTY_X_FIX_MARGIN_RATE_FAR
                                    ELSE DMX.LIST_FUTURE_PERIOD_QTY_X_SPOT_PRICE_NEAR
                                END
                            ELSE NULL
                        END
                    ELSE NULL
                END AS NOTIONAL_AMT_EFFECTI_DATE_LEG2
            FROM DUAL
		) sub_notional_amt_effecti_date
		--<REGTR-5313>
		CROSS APPLY
		(
            SELECT
				TRIM(',' FROM
					(
						CASE
							WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND NVL (DMX.THD_INITIALPAYMENT_AMT,0) != 0 THEN 'UFRO'
							ELSE NULL
						END
						|| ',' || DMX.LIST_UWIN_MOP
					)
                ) AS OTH_PAYMENT_TYPE,

                TRIM(',' FROM
                            (
                                CASE
                                    WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND NVL (DMX.THD_INITIALPAYMENT_AMT,0) != 0 THEN RTRIM(TO_CHAR(FMT_ELT.FLEXIBLE_ROUND(ABS(DMX.THD_INITIALPAYMENT_AMT),2,'HALF_DOWN'),'FM999999999999999999999999999999990.99'),'.')
                                    ELSE NULL
                                END
                                || ',' || DMX.LIST_FFL_PYMT_AMT_MOP
                             )
                    ) AS OTH_PAYMENT_AMOUNT,

                TRIM(',' FROM
                            (
                                CASE
                                    WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND NVL (DMX.THD_INITIALPAYMENT_AMT,0) != 0 THEN DECODE(DMX.THD_PREMIUMCCY,'CNH','CNY',DMX.THD_PREMIUMCCY)--DMX.THD_PREMIUMCCY
                                    ELSE NULL
                                END
                                || ',' || DMX.LIST_FFL_PMT_CCY_CODE_MOP
                            )
                    ) AS OTH_PAYMENT_CURR,

                TRIM(',' FROM
                            (
                                TO_CHAR(
                                    CASE
                                        WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND NVL(DMX.THD_INITIALPAYMENT_AMT,0) != 0 THEN DMX.THD_PREMIUM_PAY_DATE
                                        ELSE NULL
                                    END,
                                    'YYYY-MM-DD')
                                || ',' || DMX.LIST_FFL_PMT_DATE_MOP
                            )
                    ) AS OTH_PAYMENT_DATE,

                TRIM(',' FROM
                            (
                                CASE
                                    WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND NVL (DMX.THD_INITIALPAYMENT_AMT,0) != 0 THEN --DECODE(DMX.THD_BUY_SELL_IND,'SELL', DMX.COUNTERPARTY_LEI,'BUY', DMX.REPORTING_PARTY_LEI,NULL)
                                        CASE
                                            WHEN DMX.THD_INITIALPAYMENT_AMT < 0 THEN DMX.REPORTING_PARTY_LEI
                                            ELSE DMX.COUNTERPARTY_LEI
                                        END
                                    ELSE NULL
                                END
                                || ',' || DMX.LIST_FFL_PMT_PAY_LEI_MOP
                            )
                    ) AS OTH_PAYMENT_PAYER,

                TRIM(',' FROM
                            (
                                CASE
                                    WHEN DMX.THD_TRD_QUALIF_VAL = 'SWP' AND NVL (DMX.THD_INITIALPAYMENT_AMT,0) != 0 THEN --DECODE(DMX.THD_BUY_SELL_IND,'SELL', DMX.REPORTING_PARTY_LEI,'BUY', DMX.COUNTERPARTY_LEI,NULL)
                                        CASE
                                            WHEN DMX.THD_INITIALPAYMENT_AMT > 0 THEN DMX.REPORTING_PARTY_LEI
                                            ELSE DMX.COUNTERPARTY_LEI
                                        END
                                    ELSE NULL
                                END
                                || ',' || DMX.LIST_FFL_PMT_RECV_LEI_MOP
                            )
                    ) AS OTH_PAYMENT_RECEIVER
            FROM DUAL
		) sub_oth_fields
        --</REGTR-5313>
)
SELECT
    --<GH_Rewrite_Work>
    REPORTABLE_CFTC,
    REPORTABLE_CSA,
    --</GH_Rewrite_Work>
    CLEARED,
    --<GH_Rewrite_Work>
    -- champ splitt  CFTC/CSA
	--CLEAR_EXCEPTION2,
	CLEAR_EXCEPTION2_CFTC,
	CLEAR_EXCEPTION2_CSA,
	--</GH_Rewrite_Work>
	REPORTING_PARTY_LEI,
	COUNTERPARTY_LEI,
	PARTY_TYP2,
	FINANCIAL_ENTITY1,
	FINANCIAL_ENTITY2,
	BUYER,
	SELLER,
	PAYER_LEG1,
	PAYER_LEG2,
	RECEIVER_LEG1,
	RECEIVER_LEG2,
	FEDERAL_ENTITY2,
	CUSTOM_BSK_IND,
	EVENT_ID,
	EVENT_TIME,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- <Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

--	ROUND (NOTIONAL1, 5) AS NOTIONAL1,
--	ROUND (NOTIONAL1, 2) AS NOTIONAL1,
    FMT_ELT.FLEXIBLE_ROUND(NOTIONAL1,2,'HALF_DOWN') AS NOTIONAL1,

--	ROUND (NOTIONAL2, 5) AS NOTIONAL2,
--	ROUND (NOTIONAL2, 2) AS NOTIONAL2,
    FMT_ELT.FLEXIBLE_ROUND(NOTIONAL2,2,'HALF_DOWN') AS NOTIONAL2,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- </Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

	DECODE (CURR1, 'CNH', 'CNY', CURR1) AS CURR1,
	DECODE (CURR2, 'CNH', 'CNY', CURR2) AS CURR2,
	NOTIONAL_AMT_EFFECTI_DATE_LEG1,
	NOTIONAL_AMT_EFFECTI_DATE_LEG2,
	EFFECTI_DATE_NOTIONAL_AMT_LEG1,
	EFFECTI_DATE_NOTIONAL_AMT_LEG2,
	END_NOTIONAL_AMOUNT_LEG1,
	END_NOTIONAL_AMOUNT_LEG2,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- <Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

--	CALL_AMOUNT_LEG1,
--	ROUND(CALL_AMOUNT_LEG1,2) AS CALL_AMOUNT_LEG1,
    FMT_ELT.FLEXIBLE_ROUND(CALL_AMOUNT_LEG1,2,'HALF_DOWN') AS CALL_AMOUNT_LEG1,

--	CALL_AMOUNT_LEG2,
--	ROUND(CALL_AMOUNT_LEG2,2) AS CALL_AMOUNT_LEG2,
	FMT_ELT.FLEXIBLE_ROUND(CALL_AMOUNT_LEG2,2,'HALF_DOWN') AS CALL_AMOUNT_LEG2,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- </Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

	DECODE (CALL_CURR_LEG1, 'CNH', 'CNY', CALL_CURR_LEG1) AS CALL_CURR_LEG1,
	DECODE (CALL_CURR_LEG2, 'CNH', 'CNY', CALL_CURR_LEG2) AS CALL_CURR_LEG2,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- <Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

--	PUT_AMOUNT_LEG1,
--	ROUND(PUT_AMOUNT_LEG1,2) AS PUT_AMOUNT_LEG1,
    FMT_ELT.FLEXIBLE_ROUND(PUT_AMOUNT_LEG1,2,'HALF_DOWN') AS PUT_AMOUNT_LEG1,

--	PUT_AMOUNT_LEG2,
--	ROUND(PUT_AMOUNT_LEG2,2) AS PUT_AMOUNT_LEG2,
    FMT_ELT.FLEXIBLE_ROUND(PUT_AMOUNT_LEG2,2,'HALF_DOWN') AS PUT_AMOUNT_LEG2,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- </Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

	DECODE (PUT_CURR_LEG1, 'CNH', 'CNY', PUT_CURR_LEG1) AS PUT_CURR_LEG1,
	DECODE (PUT_CURR_LEG2, 'CNH', 'CNY', PUT_CURR_LEG2) AS PUT_CURR_LEG2,
	LEG1_NOTIONAL_QUANTITY,
	LEG2_NOTIONAL_QUANTITY,
	QUANTITY_FREQ_LEG1,
	QUANTITY_FREQ_LEG2,
	QUANTITY_FREQ_MULTI_LEG1,
	QUANTITY_FREQ_MULTI_LEG2,
	QUANTITY_UNIT_MESURE_LEG1,
	QUANTITY_UNIT_MESURE_LEG2,
	TOTAL_QUANTITY1,
	TOTAL_QUANTITY2,
	PACKAGE_INDICATOR,
	PACKAGE_ID,
	PACKAGE_PRICE,
	PACK_CURR_PRICE,
	PACK_NOTAT_PRICE,
	PACKAGE_SPREAD,
	PACK_CURR_SPREAD,
	PACKAGE_NOTAT_SPREAD,
	FIX_RATE_DAY_CONVENTION_LEG1,
	FIX_RATE_DAY_CONVENTION_LEG2,
	FLOAT_RATE_DAY_CONVENTION_LEG1,
	FLOAT_RATE_DAY_CONVENTION_LEG2,
	FIXING_DATE_LEG1,
	FIXING_DATE_LEG2,
	FLOAT_RESET_FREQUENCY_LEG1,
	FLOAT_RESET_FREQUENCY_LEG2,
	FLOAT_RESET_FREQ_MULTI_LEG1,
	FLOAT_RESET_FREQ_MULTI_LEG2,
	OTH_PAYMENT_TYPE,
	OTH_PAYMENT_AMOUNT,
	OTH_PAYMENT_CURR,
	OTH_PAYMENT_DATE,
	OTH_PAYMENT_PAYER,
	OTH_PAYMENT_RECEIVER,
	FIX_PMT_FREQ_LEG1,
	FIX_PMT_FREQ_LEG2,
	FLOAT_PMT_FREQ_LEG1,
	FLOAT_PMT_FREQ_LEG2,
	FIX_PMT_FREQ_MULTI_LEG1,
	FIX_PMT_FREQ_MULTI_LEG2,
	FLOAT_PMT_FREQ_MULTI_LEG1,
	FLOAT_PMT_FREQ_MULTI_LEG2,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- <Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

--	EXCHANGE_RATE,
	EXCHANGE_RATE_CFTC,
	EXCHANGE_RATE_CSA,

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- </Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

	EXCHANGE_RATE_BASIS,
	--<GH_Rewrite_Work>
	--champs splitt s CFTC/CSA
--	ROUND (FIXED_RATE1, 7) AS FIXED_RATE1,
--	ROUND (FIXED_RATE2, 7) AS FIXED_RATE2,
	ROUND (FIXED_RATE1_CFTC, 7) AS FIXED_RATE1_CFTC,
	ROUND (FIXED_RATE1_CSA, 7) AS FIXED_RATE1_CSA,
	ROUND (FIXED_RATE2_CFTC, 7) AS FIXED_RATE2_CFTC,
	ROUND (FIXED_RATE2_CSA, 7) AS FIXED_RATE2_CSA,
	--</GH_Rewrite_Work>
	POST_PRICED_SWP,
	PRICE,
	PRICE_CURR,
	PRICE_NOTATION,
	PRICE_UNIT,
	--<GH_Rewrite_Work>
	--champs splitt s CFTC/CSA
--	SPREAD1,
--	SPREAD2,
--	SPREAD_CURR_LEG1,
